package main

func solve(s string, order []int64, k int64) int64 {
    const inf int64 = 1 << 60
    n := len(s)
    totalSub := int64(n) * int64(n+1) / 2
    baseSize := n + 3

    minInt := func(a, b int) int {
        if a < b {
            return a
        }
        return b
    }
    maxInt := func(a, b int) int {
        if a > b {
            return a
        }
        return b
    }
    maxInt64 := func(a, b int64) int64 {
        if a > b {
            return a
        }
        return b
    }
    minInt64 := func(a, b int64) int64 {
        if a < b {
            return a
        }
        return b
    }

    type MaxSegTree struct {
        tree []int64
        n    int
    }
    newMaxSegTree := func(size int) *MaxSegTree {
        return &MaxSegTree{
            tree: make([]int64, 4*size),
            n:    size,
        }
    }
    type MinSegTree struct {
        tree []int64
        n    int
    }
    newMinSegTree := func(size int) *MinSegTree {
        return &MinSegTree{
            tree: make([]int64, 4*size),
            n:    size,
        }
    }
    var maxTree *MaxSegTree
    var minTree *MinSegTree

    maxTree = newMaxSegTree(baseSize)
    minTree = newMinSegTree(baseSize)
    for i := range maxTree.tree {
        maxTree.tree[i] = -1
    }
    for i := range minTree.tree {
        minTree.tree[i] = inf
    }

    var updateMaxTree func(int, int, int, int, int64)
    updateMaxTree = func(v, tl, tr, idx int, val int64) {
        if tl == tr {
            maxTree.tree[v] = val
            return
        }
        tm := (tl + tr) / 2
        if idx <= tm {
            updateMaxTree(2*v+1, tl, tm, idx, val)
        } else {
            updateMaxTree(2*v+2, tm+1, tr, idx, val)
        }
        maxTree.tree[v] = maxInt64(maxTree.tree[2*v+1], maxTree.tree[2*v+2])
    }
    var queryMaxTree func(int, int, int, int, int) int64
    queryMaxTree = func(v, tl, tr, l, r int) int64 {
        if l > r {
            return -1
        }
        if tl == l && tr == r {
            return maxTree.tree[v]
        }
        tm := (tl + tr) / 2
        leftRes := queryMaxTree(2*v+1, tl, tm, l, minInt(tm, r))
        rightRes := queryMaxTree(2*v+2, tm+1, tr, maxInt(tm+1, l), r)
        return maxInt64(leftRes, rightRes)
    }
    maxTree.Update := func(idx int, val int64) {
        updateMaxTree(0, 0, baseSize-1, idx, val)
    }
    maxTree.Query := func(l, r int) int64 {
        return queryMaxTree(0, 0, baseSize-1, l, r)
    }

    var updateMinTree func(int, int, int, int, int64)
    updateMinTree = func(v, tl, tr, idx int, val int64) {
        if tl == tr {
            minTree.tree[v] = val
            return
        }
        tm := (tl + tr) / 2
        if idx <= tm {
            updateMinTree(2*v+1, tl, tm, idx, val)
        } else {
            updateMinTree(2*v+2, tm+1, tr, idx, val)
        }
        minTree.tree[v] = minInt64(minTree.tree[2*v+1], minTree.tree[2*v+2])
    }
    var queryMinTree func(int, int, int, int, int) int64
    queryMinTree = func(v, tl, tr, l, r int) int64 {
        if l > r {
            return inf
        }
        if tl == l && tr == r {
            return minTree.tree[v]
        }
        tm := (tl + tr) / 2
        leftRes := queryMinTree(2*v+1, tl, tm, l, minInt(tm, r))
        rightRes := queryMinTree(2*v+2, tm+1, tr, maxInt(tm+1, l), r)
        return minInt64(leftRes, rightRes)
    }
    minTree.Update := func(idx int, val int64) {
        updateMinTree(0, 0, baseSize-1, idx, val)
    }
    minTree.Query := func(l, r int) int64 {
        return queryMinTree(0, 0, baseSize-1, l, r)
    }

    maxTree.Update(0, -1)
    minTree.Update(0, -1)
    maxTree.Update(n+1, int64(n))
    minTree.Update(n+1, int64(n))

    invalidTotal := totalSub

    for t := 0; t < n; t++ {
        x := order[t]
        baseIndex := int(x) + 1

        pred := maxTree.Query(0, baseIndex)
        succ := minTree.Query(baseIndex, baseSize-1)

        L := succ - pred - 1
        if L < 0 {
            L = 0
        }
        oldCount := L * (L + 1) / 2

        len1 := x - (pred + 1)
        if len1 < 0 {
            len1 = 0
        }
        len2 := (succ - 1) - x
        if len2 < 0 {
            len2 = 0
        }
        newCount := len1*(len1+1)/2 + len2*(len2+1)/2

        maxTree.Update(baseIndex, x)
        minTree.Update(baseIndex, x)

        invalidTotal = invalidTotal - oldCount + newCount
        validCount := totalSub - invalidTotal

        if validCount >= k {
            return int64(t)
        }
    }

    return -1
}
