### Approach
1. **Initial Setup**: Calculate the total number of possible substrings in the original string, which is given by the formula `n*(n+1)/2`.
2. **Tracking Segments**: Maintain a list of segments (contiguous blocks of non-replaced characters) in the string. Initially, the entire string is a single segment.
3. **Processing Replacement Order**: For each time step `t`, process the replacement at the specified index:
   - **Find the Segment**: Identify the segment containing the current replacement index.
   - **Update Segments**: Split this segment into two new segments (if applicable) around the replacement index.
   - **Update Invalid Substrings**: Calculate the change in the count of invalid substrings (substrings without any '*') resulting from the split. This involves:
     - Subtracting the invalid substrings count of the original segment.
     - Adding the invalid substrings counts of the new segments (if any).
4. **Check Condition**: After each replacement, check if the number of valid substrings (total substrings minus invalid substrings) meets or exceeds `k`. If so, return the current time `t`.
5. **Termination**: If after processing all replacements the condition is never met, return -1.

### Solution Code
```go
func solve(s string, order []int64, k int64) int64 {
    n := len(s)
    totalSubs := int64(n) * int64(n+1) / 2
    segments := []struct{ l, r int }{ {0, n-1} }
    invalid := totalSubs

    for t := 0; t < n; t++ {
        idx := int(order[t])
        segIdx := -1
        for i, seg := range segments {
            if seg.l <= idx && idx <= seg.r {
                segIdx = i
                break
            }
        }
        if segIdx == -1 {
            continue
        }
        seg := segments[segIdx]
        segments = append(segments[:segIdx], segments[segIdx+1:]...)

        L := int64(seg.r - seg.l + 1)
        invalidSegment := L * (L+1) / 2

        left_l, left_r := seg.l, idx-1
        right_l, right_r := idx+1, seg.r

        var leftValid, rightValid int64
        if left_r >= left_l {
            leftLen := left_r - left_l + 1
            leftValid = int64(leftLen) * int64(leftLen+1) / 2
        }
        if right_r >= right_l {
            rightLen := right_r - right_l + 1
            rightValid = int64(rightLen) * int64(rightLen+1) / 2
        }

        invalid = invalid - invalidSegment + leftValid + rightValid
        valid := totalSubs - invalid
        if valid >= k {
            return int64(t)
        }

        if left_l <= left_r {
            segments = append(segments, struct{ l, r int }{left_l, left_r})
        }
        if right_l <= right_r {
            segments = append(segments, struct{ l, r int }{right_l, right_r})
        }
    }

    return -1
}
